const lead = $input.first().json[0] || $input.first().json;

const prompt = `You are an experienced business development strategist for digital services in India.

Create a detailed approach strategy for pitching website/digital services to:
- Business: ${lead.business_name}
- Category: ${lead.category || 'local business'}
- Location: ${lead.address || ''}, ${lead.city || ''}
- Google Rating: ${lead.google_rating || 'Not rated'}
- Has Website: No
- Phone: ${lead.phone || 'N/A'}

Generate a comprehensive strategy in this exact JSON format:
{
  "executive_summary": "2-3 sentences on why this business needs a website",
  "pitch_angle": "The specific persuasion angle to use",
  "competitor_insight": "What similar businesses are doing online",
  "service_package": {
    "recommended_services": ["website", "google_maps_optimization"],
    "starter_price": "₹4,999",
    "growth_price": "₹9,999",
    "timeline": "5 days"
  },
  "outreach_plan": {
    "best_channel": "whatsapp",
    "best_time": "2-4 PM weekdays",
    "opening_line": "The exact first sentence to say",
    "key_talking_points": ["point1", "point2", "point3"]
  },
  "objections_and_handlers": [
    { "objection": "I don't need a website", "response": "..." },
    { "objection": "It's too expensive", "response": "..." }
  ],
  "revenue_estimate": {
    "initial_deal": "₹X,XXX",
    "recurring_monthly": "₹X,XXX"
  },
  "difficulty_score": 3,
  "next_best_action": "The single most impactful thing to do first"
}

Be specific to Indian market with INR pricing.`;

return [{ json: { prompt, lead } }];

const response = $input.first().json;
const triggerData = $('Webhook Trigger').first().json.body;

let strategy;
try {
  const text = response.candidates[0].content.parts[0].text;
  strategy = JSON.parse(text);
} catch (e) {
  strategy = { executive_summary: 'Failed to generate strategy. Please try again.', difficulty_score: 3 };
}

return [{
  json: {
    lead_id: triggerData.lead_id,
    user_id: triggerData.user_id,
    content_json: JSON.stringify(strategy),
    executive_summary: strategy.executive_summary || '',
    pitch_angle: strategy.pitch_angle || '',
    recommended_services: strategy.service_package?.recommended_services || [],
    pricing_suggestion: strategy.service_package?.starter_price || '',
    difficulty_score: strategy.difficulty_score || 3,
    status: 'draft'
  }
}];
